// Generated: instrument sample audio as base64 — lets the
// note-player load .ogg under file:// (where fetch is blocked).
// Companion to midi-blob.js; same MKH.<...>Bytes() pattern.
window.MKH = window.MKH || {};
MKH._instrumentBlobs = {"saksofon": "", "ksilofon": "", "piano": "", "lagu_ani": "", "guitar": "", "skripka": "", "baian": "", "truba": "", "kolokol": "", "fleita": ""};

MKH.instrumentBytes = function (name) {
    var b64 = MKH._instrumentBlobs && MKH._instrumentBlobs[name];
    if (!b64) return null;
    var bin = atob(b64);
    var buf = new ArrayBuffer(bin.length);
    var u8  = new Uint8Array(buf);
    for (var i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
    return buf;
};
